	note = {PMC9040104}
}

@ARTICLE{10.1161/CIRCULATIONAHA.121.058229,
	author = {Lüsebrink E and Kellnar A and Krieg K, Binzenhöfer L and Scherer C and Zimmer S and Schrage B and Fichtner S and Petzold T and Braun D and Peterss S and Brunner S and Hagl C and Westermann D and Hausleiter J and Massberg S and Thiele H, Schäfer A and Orban M},
	title = {Percutaneous Transvalvular Microaxial Flow Pump Support in Cardiology.},
	journal = {Circulation},
	year = {2022},
	abstract = {The Impella device (Impella, Abiomed, Danvers, MA) is a percutaneous transvalvular microaxial flow pump that is currently used for (1) cardiogenic shock, (2) left ventricular unloading (combination of venoarterial extracorporeal membrane oxygenation and Impella concept), (3) high-risk percutaneous coronary interventions, (4) ablation of ventricular tachycardia, and (5) treatment of right ventricular failure. Impella-assisted forward blood flow increased mean arterial pressure and cardiac output, peripheral tissue perfusion, and coronary blood flow in observational studies and some randomized trials. However, because of the need for large-bore femoral access (14 F for the commonly used Impella CP device) and anticoagulation, the incidences of bleeding and ischemic complications are as much as 44% and 18%, respectively. Hemolysis is reported in as many as 32% of patients and stroke in as many as 13%. Despite the rapidly growing use of the Impella device, there are still insufficient data on its effect on outcome and complications on the basis of large, adequately powered randomized controlled trials. The only 2 small and also underpowered randomized controlled trials in cardiogenic shock comparing Impella versus intra-aortic balloon pump did not show improved mortality. Several larger randomized controlled trials are currently recruiting patients or are in preparation in cardiogenic shock (DanGer Shock [Danish-German Cardiogenic Shock Trial; NCT01633502]), left ventricular unloading (DTU-STEMI [Door-To-Unload in ST-Segment-Elevation Myocardial Infarction; NCT03947619], UNLOAD ECMO [Left Ventricular Unloading to Improve Outcome in Cardiogenic Shock Patients on VA-ECMO], and REVERSE [A Prospective Randomised Trial of Early LV Venting Using Impella CP for Recovery in Patients With Cardiogenic Shock Managed With VA ECMO; NCT03431467]) and high-risk percutaneous coronary intervention (PROTECT IV [Impella-Supported PCI in High-Risk Patients With Complex Coronary Artery Disease and Reduced Left Ventricular Function; NCT04763200]).},
	doi = {10.1161/CIRCULATIONAHA.121.058229},
	pmid = {35436135 [Indexed for MEDLINE]}
}

@ARTICLE{10.1177/10892532221080382,
	author = {Knio ZO and Thiele RH and Wright WZ and Mazimba S and Naik BI and Hulse MC},
	title = {A Novel Hemodynamic Index of Post-operative Right Heart Dysfunction Predicts Mortality in Cardiac Surgical Patients.},
	journal = {Semin Cardiothorac Vasc Anesth},
	year = {2022},
	abstract = {INTRODUCTION: This study aimed to investigate whether mortality following cardiac surgery was associated with the pulmonary artery pulsatility index (PAPi): pulmonary artery pulse pressure divided by central venous pressure (CVP), and a novel index: mean pulmonary artery pressure (mPAP) minus CVP. METHODS: This retrospective analysis investigated all cardiac surgery patients in the Society of Thoracic Surgeons registry at a single academic medical center from January 2017 through March 2020 (n = 1510). The primary and secondary outcomes were mortality at 1 year and serum creatinine increase during index surgical admission, respectively. CVP, mPAP, PAPi, mPAP-CVP gradient, mean arterial pressure (MAP), and cardiac index (CI) were sampled continually from invasive hemodynamic monitors post-operatively. Associations with mortality were tested with univariate and multivariate analyses. The relationship with serum creatinine was investigated with Pearson's correlation at alpha = .05. RESULTS: One-year mortality was observed in 44/1200 patients (3.7%). On univariate analysis, mortality was associated with minimums for mPAP, MAP, and CI and maximums for CVP, mPAP, PAPi, mPAP-CVP gradient, and CI (all P < .10). Model selection revealed that the only independently predictive parameters were minimum MAP (AOR = .880 [.819-.944]), maximum mPAP-CVP gradient (AOR = 1.082 [1.031-1.133]), and maximum CI (AOR = 1.421 [.928-2.068]), with model c-statistic = .770. A maximum mPAP-CVP gradient >20.5 predicted mortality with 54.5% sensitivity and 79.30% specificity, maintaining significance on survival analysis (P < .001). Peak increase in serum creatinine from baseline demonstrated a weak association with all parameters (max |r| = .33). CONCLUSIONS: Mortality was not predicted by the post-operative PAPi; rather, it was independently predicted by the mPAP-CVP gradient, MAP, and CI.},
	doi = {10.1177/10892532221080382},
	pmid = {35332827 [Indexed for MEDLINE]}
}
